// macOS menubar tray + anchored popover. Phase 1.7 refinements per
// the deepening review:
//   • Real 16×16/@2x template PNG (generated by scripts/generate-tray-icon.mjs
//     from the brand mark SVG). Template images automatically adapt
//     to dark / light / accent menubars — setTitle() text doesn't.
//   • Popover dismiss-on-blur with a 120ms debounce + DevTools open
//     guard + cursor-bounds check, matching Raycast / Linear / Bartender
//     patterns. Avoids the false-positives the original blur-only
//     handler caused (DevTools focus, dragging the popover, focus
//     hopping to a child popover all looked like "click outside").
//   • screen.getDisplayMatching(trayBounds) for multi-display anchoring.
//   • Right-click opens a real Menu (Quit / Open / Settings) — popover
//     is for the rich UI, the native menu is the fallback.

import { existsSync } from "node:fs";
import { join } from "node:path";
import {
  app,
  ipcMain,
  Menu,
  type MenuItemConstructorOptions,
  nativeImage,
  screen,
  Tray,
  type BrowserWindow
} from "electron";
import { EVENT_CHANNELS } from "@pwrsnap/shared";
import { bus } from "./command-bus";
import { getMainLogger } from "./log";
import { createTrayWindow, positionTrayWindow } from "./window";

const log = getMainLogger("pwrsnap:tray");

const BLUR_DISMISS_DEBOUNCE_MS = 120;

/**
 * Extra menu items appended to the right-click menu (after a
 * separator). Used by the dev seeder to add "Seed perf dataset > …"
 * entries in DEV builds. Empty in production. Not a registration API
 * with deduplication — caller controls the array.
 */
let extraMenuItems: MenuItemConstructorOptions[] = [];

/**
 * Append items to the tray's right-click menu. Returns a `restore`
 * function that drops the items. Call from `registerDevSeeder()`.
 */
export function setExtraTrayMenuItems(items: MenuItemConstructorOptions[]): () => void {
  extraMenuItems = items;
  return () => {
    extraMenuItems = [];
  };
}
const TRAY_RESIZE_CHANNEL = "tray:resize";

/** Hard floor + ceiling so a renderer bug can't shrink to nothing or grow off-screen.
 *  Ceiling raised from 720 → 880 to fit the redesigned tray: header +
 *  Quick Capture button + 6-mode grid + 120px last-snap preview +
 *  Low/Med/High copy button row sums to ~480px on its own; with a
 *  tall capture (16:10 preview at full width) and the longest font
 *  fallback metrics it can land north of 720. The popover is anchored
 *  top-down from the menubar tray icon, so growing taller doesn't
 *  push off-screen — Electron clamps to workArea automatically. */
const TRAY_HEIGHT_MIN = 200;
const TRAY_HEIGHT_MAX = 880;
/** Window width is fixed by the design — must match `.ps-tray { width }`
    in library.css. Bumped from 380 → 440 because the 2-column mode
    grid (Region/Window, Full/All, Scrolling/Timed) was clipping the
    right column at 380, especially with multi-key shortcuts like
    ⌘⇧F that need 56px just for the kbds. */
const TRAY_WIDTH = 440;

let tray: Tray | null = null;
let trayWindow: BrowserWindow | null = null;
let pendingDismiss: ReturnType<typeof setTimeout> | null = null;

/**
 * Synchronously hide the tray popover, bypassing the 120ms blur-dismiss
 * debounce. Called from the capture flow right before we shell out to
 * `screencapture` so the popover doesn't show up in the captured frame.
 *
 * The tray popover is a `BrowserWindow` (not an `NSStatusItem` menu),
 * so it does NOT auto-dismiss on click the way a real status-bar menu
 * does — we have to dismiss it ourselves. Belt-and-suspenders against
 * a future change to a real `NSStatusItem`-backed menu (which would
 * dismiss synchronously, and then this becomes a defensible no-op).
 *
 * Idempotent and null-safe — calling on a destroyed or already-hidden
 * window is a no-op. Cancels any pending blur-debounce timeout so we
 * don't get a double-hide jitter when the queued timer fires later.
 */
export function hideTrayPopoverIfVisible(): void {
  if (pendingDismiss !== null) {
    clearTimeout(pendingDismiss);
    pendingDismiss = null;
  }
  if (trayWindow !== null && !trayWindow.isDestroyed() && trayWindow.isVisible()) {
    trayWindow.hide();
  }
}

function resolveTrayIconPath(): string {
  // Production: shipped under Contents/Resources/ via electron-builder.yml's
  // `extraResources`. nativeImage auto-loads the @2x/@3x siblings when
  // given the base path, as long as they're in the same directory.
  const productionPath = join(process.resourcesPath, "tray-icon-template.png");
  if (existsSync(productionPath)) return productionPath;
  // Dev: served straight out of the workspace `build/` dir.
  return join(app.getAppPath(), "build/tray-icon-template.png");
}

function ensureTrayWindow(): BrowserWindow {
  if (trayWindow !== null && !trayWindow.isDestroyed()) return trayWindow;
  const window = createTrayWindow();
  trayWindow = window;
  wireBlurDismiss(window);
  // Tell the renderer to re-measure whenever the session zoom factor
  // changes. We can't rely on ResizeObserver alone — Chromium does
  // not fire layout-resize observations for pure zoom changes when
  // the underlying CSS-pixel content height happens to land at the
  // same value, and `setContentSize` is in DIP, so a stale
  // CSS-pixel-height post would compute a wrong DIP after zoom
  // changed. The IPC kicks the renderer to re-post; the resize
  // handler reads the new zoomFactor and converts.
  window.webContents.on("zoom-changed", () => {
    if (window.isDestroyed()) return;
    window.webContents.send(EVENT_CHANNELS.popoverRemeasure, {});
  });
  window.on("closed", () => {
    if (trayWindow === window) trayWindow = null;
  });
  return window;
}

/**
 * Listen for tray-renderer resize requests and `setContentSize` so the
 * popover hugs its content. Each call also re-positions to keep the
 * top-right corner anchored under the tray icon (otherwise growing
 * down would push the popover off-screen on a tall display).
 *
 * Idempotent — safe to call from both the production `installTray`
 * boot path and the E2E `showTrayPopoverForE2E` test helper without
 * stacking duplicate ipcMain listeners.
 */
let trayResizeChannelWired = false;
function wireTrayResizeChannel(): void {
  if (trayResizeChannelWired) return;
  trayResizeChannelWired = true;
  ipcMain.on(TRAY_RESIZE_CHANNEL, (_event, payload: unknown) => {
    if (
      payload === null ||
      typeof payload !== "object" ||
      typeof (payload as { height: unknown }).height !== "number"
    ) {
      return;
    }
    const requestedCss = (payload as { height: number }).height;
    if (!Number.isFinite(requestedCss)) return;
    if (trayWindow === null || trayWindow.isDestroyed()) return;
    // Renderer measures in CSS pixels (post-zoom). `setContentSize`
    // takes DIP (zoom-independent). When the session's zoomFactor is
    // not 1.0 (e.g. user Cmd-+'d in the library — zoom is shared
    // per-origin via Chromium's HostZoomMap), the two units diverge:
    // a 600 CSS px tall popover at 1.32× zoom is 600 × 1.32 ≈ 792
    // DIP. Without this conversion, the BrowserWindow ends up
    // shorter than the rendered content needs and the popover
    // visibly clips.
    const zoom = trayWindow.webContents.zoomFactor;
    const requestedDip = Math.ceil(requestedCss * zoom);
    const clamped = Math.max(TRAY_HEIGHT_MIN, Math.min(TRAY_HEIGHT_MAX, requestedDip));
    if (trayWindow.getContentSize()[1] === clamped) return;
    // Belt-and-braces: every resize call lifts the implicit minimum
    // size first. The createTrayWindow call already does this once on
    // first construction, but if anything later re-asserts a min size
    // (an unrelated Electron API call, a future BrowserWindow.setBounds
    // wrapper, etc.) the resize would silently clamp again. Cheap to
    // re-call — Electron coalesces same-value setMinimumSize calls.
    trayWindow.setMinimumSize(0, 0);
    trayWindow.setContentSize(TRAY_WIDTH, clamped, false);
    if (tray !== null && trayWindow.isVisible()) {
      positionTrayWindow(trayWindow, tray.getBounds());
    }
  });
}

/**
 * Dismiss-on-blur with two false-positive guards:
 *   - DevTools opened on the tray (developer is debugging)
 *   - Re-focused during the debounce (false-positive blur from a
 *     macOS focus hop)
 *
 * The cursor-inside-bounds check that used to live here was
 * dropping legitimate dismissals — right-clicking the dock icon
 * fires blur but the cursor often grazes the tray window during
 * the debounce, which the old check interpreted as "user is still
 * here." For a transient popover we want to err on dismissing.
 */
function wireBlurDismiss(window: BrowserWindow): void {
  window.on("blur", () => {
    if (pendingDismiss !== null) return;
    pendingDismiss = setTimeout(() => {
      pendingDismiss = null;
      if (trayWindow === null || trayWindow.isDestroyed()) return;
      // DevTools open on the tray = developer using it; never auto-dismiss.
      if (trayWindow.webContents.isDevToolsOpened()) return;
      // If the window regained focus during the debounce window, abort.
      if (trayWindow.isFocused()) return;
      trayWindow.hide();
    }, BLUR_DISMISS_DEBOUNCE_MS);
  });
  window.on("focus", () => {
    if (pendingDismiss !== null) {
      clearTimeout(pendingDismiss);
      pendingDismiss = null;
    }
  });
}

export function installTray(): Tray {
  if (tray !== null) return tray;

  wireTrayResizeChannel();

  const iconPath = resolveTrayIconPath();
  const icon = nativeImage.createFromPath(iconPath);
  if (icon.isEmpty()) {
    log.warn("tray icon image is empty — falling back to setTitle text", { iconPath });
  }
  icon.setTemplateImage(true);

  tray = new Tray(icon);
  tray.setToolTip("PwrSnap — ⌘⇧P to capture");
  tray.setIgnoreDoubleClickEvents(true);

  tray.on("click", () => toggleTrayWindow());
  tray.on("right-click", () => {
    // Always dismiss the popover before the context menu appears —
    // having both visible at once is confusing UX (and was the
    // dock-icon-right-click reproduction the user reported).
    if (trayWindow !== null && !trayWindow.isDestroyed() && trayWindow.isVisible()) {
      trayWindow.hide();
    }
    const baseTemplate: MenuItemConstructorOptions[] = [
      {
        label: "Capture (Auto)…",
        accelerator: "CommandOrControl+Shift+P",
        click: () => {
          void bus.dispatch("capture:interactive", { mode: "auto" }, { principal: "ipc" });
        }
      },
      { type: "separator" },
      {
        label: "Open Library",
        click: () => {
          void bus.dispatch("library:focus", {}, { principal: "ipc" });
        }
      },
      {
        label: "Settings…",
        accelerator: "CommandOrControl+,",
        click: () => {
          void bus.dispatch("settings:open", {}, { principal: "ipc" });
        }
      }
    ];
    const extras = extraMenuItems.length > 0
      ? [{ type: "separator" } as MenuItemConstructorOptions, ...extraMenuItems]
      : [];
    const menu = Menu.buildFromTemplate([
      ...baseTemplate,
      ...extras,
      { type: "separator" },
      { role: "quit" }
    ]);
    tray?.popUpContextMenu(menu);
  });

  log.info("tray installed", { iconPath });
  return tray;
}

function toggleTrayWindow(): void {
  const window = ensureTrayWindow();
  if (window.isVisible()) {
    window.hide();
    return;
  }
  const bounds = tray!.getBounds();
  positionTrayWindow(window, bounds);
  // Apply vibrancy *after* position so external displays don't render
  // it opaque — known Electron quirk on Sonoma+ multi-monitor setups.
  try {
    window.setVibrancy("popover");
  } catch {
    /* not all macOS versions accept all vibrancy values; non-fatal */
  }
  // Show, then promote to key window. The two-step matters:
  //
  //   1. `showInactive()` paints the panel without activating the
  //      owning app (this is what `type: 'panel'` is for — a
  //      non-activating NSPanel).
  //   2. `focus()` makes the panel the macOS *key window*. On
  //      Electron 28+ with PR #40307 this is non-activating for
  //      panel windows — the panel becomes key, but the app does
  //      NOT come to the foreground.
  //
  // Why bother making it key? Click-outside-to-dismiss. Cocoa fires
  // `NSWindowDidResignKeyNotification` (which Electron surfaces as
  // `blur`) only when the panel was previously key. Without step 2
  // the popover never becomes key, so blur never fires, so the
  // dismiss-on-blur handler in wireBlurDismiss can't see clicks
  // outside the popover. Promoting to key on show reverses that —
  // any click outside the popover (other apps, the desktop, another
  // PwrSnap window) costs the panel its key status and fires blur.
  //
  // The Library-cascade concern from the original implementation
  // (Cocoa picking the next-key window of our app when the panel
  // hides) is handled by the floating-level focus-sink installed
  // at startup — see focus-sink.ts.
  window.showInactive();
  window.focus();
}

export function disposeTray(): void {
  if (pendingDismiss !== null) {
    clearTimeout(pendingDismiss);
    pendingDismiss = null;
  }
  ipcMain.removeAllListeners(TRAY_RESIZE_CHANNEL);
  trayResizeChannelWired = false;
  if (trayWindow !== null && !trayWindow.isDestroyed()) {
    trayWindow.destroy();
    trayWindow = null;
  }
  if (tray !== null) {
    tray.destroy();
    tray = null;
  }
}

/**
 * E2E-only: ensure the tray popover BrowserWindow exists, the resize
 * channel is wired, and the window is visible. Skips the `Tray` icon
 * creation that `installTray()` does — tests don't need a menubar
 * NSStatusItem, and creating one in headless CI environments is
 * unreliable.
 *
 * Positions the popover at a fixed top-left location on the primary
 * display so spec assertions about bounds are stable across machines.
 */
export function showTrayPopoverForE2E(): void {
  wireTrayResizeChannel();
  const window = ensureTrayWindow();
  // Stable test position: top-left of the primary display, indented
  // a few pixels off the menubar. Production positioning happens via
  // positionTrayWindow + the tray icon's bounds; tests don't have a
  // tray icon, so we just pin the window somewhere predictable.
  const primary = screen.getPrimaryDisplay();
  const wa = primary.workArea;
  window.setPosition(wa.x + 8, wa.y + 8, false);
  window.showInactive();
  window.focus();
}

/** E2E-only: hide the tray popover synchronously (no debounce). */
export function hideTrayPopoverForE2E(): void {
  hideTrayPopoverIfVisible();
}
